return [
  {
    json: {
      tab: 'LOS ANGELES',
      range: 'A1:W1500',
    },
  },
  {
    json: {
      tab: 'ORANGE COUNTY',
      range: 'A1:W1500',
    },
  },
  {
    json: {
      tab: 'RIVERSIDE',
      range: 'A1:W1500',
    },
  },
];

const input = $input.first().json;

// Tu HTTP Request está devolviendo la respuesta dentro de "body"
const response = input.body || input;

const valueRanges = response.valueRanges || [];

const COL = {
  SCORE: 0,
  QUALIFIED: 1,
  AGENT: 2,
  OFFICE: 3,
  DATE: 4,
  LEAD: 5,
  PHONE: 6,
  RECORDING: 7,
  DURATION: 8,
  COMMENTS: 21,
  STATUS: 22,
};

const eligible = [];

function cell(row, index) {
  return String(row?.[index] ?? '').trim();
}

function getTabName(range) {
  // Ejemplos:
  // "'LOS ANGELES'!A1:W1218"
  // "RIVERSIDE!A1:W651"
  return String(range || '')
    .split('!')[0]
    .replace(/^'/, '')
    .replace(/'$/, '')
    .trim();
}

for (const valueRange of valueRanges) {
  const tab = getTabName(valueRange.range);
  const values = valueRange.values || [];

  // values[0] son headers. La data real empieza en la fila 2.
  for (let i = 1; i < values.length; i++) {
    const row = values[i];
    const rowNumber = i + 1;

    const score = cell(row, COL.SCORE);
    const qualified = cell(row, COL.QUALIFIED).toUpperCase();
    const agent = cell(row, COL.AGENT);
    const office = cell(row, COL.OFFICE);
    const date = cell(row, COL.DATE);
    const lead = cell(row, COL.LEAD);
    const phone = cell(row, COL.PHONE);
    const recordingUrl = cell(row, COL.RECORDING);
    const existingDuration = cell(row, COL.DURATION);
    const existingComment = cell(row, COL.COMMENTS);
    const status = cell(row, COL.STATUS);

    const isNewUnprocessed =
      score === '0' &&
      qualified === 'NO' &&
      recordingUrl.startsWith('http') &&
      status === '';

    const isPartialCompleted =
      status === 'Viktor Completed' &&
      recordingUrl.startsWith('http') &&
      (!agent || !existingDuration || !existingComment);

    if (!isNewUnprocessed && !isPartialCompleted) {
      continue;
    }

    eligible.push({
      json: {
        tab,
        rowNumber,
        score,
        qualified,
        agent,
        office,
        date,
        lead,
        phone,
        recordingUrl,
        existingDuration,
        existingComment,
        existingStatus: status,
        eligibilityReason: isNewUnprocessed
          ? 'new_unprocessed_row'
          : 'partial_completed_row_needs_patch',
      },
    });
  }
}

return eligible;

const items = $input.all();

function formatDuration(totalSeconds) {
  const seconds = Math.round(totalSeconds);

  const h = Math.floor(seconds / 3600);
  const m = Math.floor((seconds % 3600) / 60);
  const s = seconds % 60;

  if (h > 0) {
    return `${h}:${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`;
  }

  return `${m}:${String(s).padStart(2, '0')}`;
}

function readWavDuration(buffer) {
  const riff = buffer.toString('ascii', 0, 4);
  const wave = buffer.toString('ascii', 8, 12);

  if (riff !== 'RIFF' || wave !== 'WAVE') {
    throw new Error('Audio file is not a valid WAV file.');
  }

  let offset = 12;
  let byteRate = null;
  let dataSize = null;

  while (offset + 8 <= buffer.length) {
    const chunkId = buffer.toString('ascii', offset, offset + 4);
    const chunkSize = buffer.readUInt32LE(offset + 4);
    const chunkDataStart = offset + 8;

    if (chunkId === 'fmt ') {
      byteRate = buffer.readUInt32LE(chunkDataStart + 8);
    }

    if (chunkId === 'data') {
      dataSize = chunkSize;
      break;
    }

    offset = chunkDataStart + chunkSize;

    // WAV chunks are aligned to even bytes
    if (offset % 2 !== 0) {
      offset += 1;
    }
  }

  if (!byteRate || !dataSize) {
    throw new Error('Could not read WAV duration from audio header.');
  }

  return dataSize / byteRate;
}

const output = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];

  if (!item.binary?.audio) {
    throw new Error(`Item ${i} does not contain binary.audio`);
  }

  const audioBuffer = await this.helpers.getBinaryDataBuffer(i, 'audio');
  const durationSeconds = readWavDuration(audioBuffer);
  const durationFormatted = formatDuration(durationSeconds);

  output.push({
    json: {
      ...item.json,
      durationSeconds,
      durationFormatted,
      durationForSheet: durationFormatted,
      audioFileName: item.binary.audio.fileName || null,
      audioMimeType: item.binary.audio.mimeType || null,
      audioFileSize: item.binary.audio.fileSize || null,
    },
    binary: item.binary,
  });
}

return output;

const items = $input.all();

const MAX_DIRECT_FILE_BYTES = 20 * 1024 * 1024; // Safe margin below OpenAI 25 MB upload limit
const DIRECT_DURATION_SECONDS = 20 * 60; // 20 minutes
const PREFERRED_SEGMENT_SECONDS = 10 * 60; // 10 minutes
const OVERLAP_SECONDS = 10; // Helps avoid cutting speech at exact segment boundary
const MIN_SEGMENT_SECONDS = 1;

function parseFileSizeBytes(value) {
  if (typeof value === 'number' && Number.isFinite(value)) return value;

  const text = String(value || '').trim();
  if (!text) return 0;

  const match = text.match(/^([\d.]+)\s*(B|KB|MB|GB|KiB|MiB|GiB)?$/i);
  if (!match) return 0;

  const number = Number(match[1]);
  const unit = (match[2] || 'B').toUpperCase();

  const factor = {
    B: 1,
    KB: 1000,
    MB: 1000 * 1000,
    GB: 1000 * 1000 * 1000,
    KIB: 1024,
    MIB: 1024 * 1024,
    GIB: 1024 * 1024 * 1024,
  }[unit] || 1;

  return Math.round(number * factor);
}

function parseWav(buffer) {
  const riff = buffer.toString('ascii', 0, 4);
  const wave = buffer.toString('ascii', 8, 12);

  if (riff !== 'RIFF' || wave !== 'WAVE') {
    throw new Error('Audio segmentation currently expects a valid WAV file.');
  }

  let offset = 12;
  let fmtData = null;
  let dataStart = null;
  let dataSize = null;

  while (offset + 8 <= buffer.length) {
    const chunkId = buffer.toString('ascii', offset, offset + 4);
    const chunkSize = buffer.readUInt32LE(offset + 4);
    const chunkDataStart = offset + 8;

    if (chunkId === 'fmt ') {
      fmtData = Buffer.from(buffer.subarray(chunkDataStart, chunkDataStart + chunkSize));
    }

    if (chunkId === 'data') {
      dataStart = chunkDataStart;
      dataSize = chunkSize;
      break;
    }

    offset = chunkDataStart + chunkSize;
    if (offset % 2 !== 0) offset += 1;
  }

  if (!fmtData || dataStart === null || dataSize === null) {
    throw new Error('Could not find required WAV fmt/data chunks.');
  }

  if (fmtData.length < 16) {
    throw new Error('Invalid WAV fmt chunk.');
  }

  const audioFormat = fmtData.readUInt16LE(0);
  const channels = fmtData.readUInt16LE(2);
  const sampleRate = fmtData.readUInt32LE(4);
  const byteRate = fmtData.readUInt32LE(8);
  const blockAlign = fmtData.readUInt16LE(12);
  const bitsPerSample = fmtData.readUInt16LE(14);

  if (!byteRate || !blockAlign) {
    throw new Error('Invalid WAV byteRate/blockAlign values.');
  }

  const durationSeconds = dataSize / byteRate;

  return {
    fmtData,
    dataStart,
    dataSize,
    audioFormat,
    channels,
    sampleRate,
    byteRate,
    blockAlign,
    bitsPerSample,
    durationSeconds,
  };
}

function createWavBuffer(fmtData, dataSlice) {
  let slice = dataSlice;

  // WAV chunks are even-byte aligned. Usually already true because blockAlign is even.
  if (slice.length % 2 !== 0) {
    slice = Buffer.concat([slice, Buffer.from([0])]);
  }

  const riffSize = 4 + (8 + fmtData.length) + (8 + slice.length);

  const riffHeader = Buffer.alloc(12);
  riffHeader.write('RIFF', 0, 4, 'ascii');
  riffHeader.writeUInt32LE(riffSize, 4);
  riffHeader.write('WAVE', 8, 4, 'ascii');

  const fmtHeader = Buffer.alloc(8);
  fmtHeader.write('fmt ', 0, 4, 'ascii');
  fmtHeader.writeUInt32LE(fmtData.length, 4);

  const dataHeader = Buffer.alloc(8);
  dataHeader.write('data', 0, 4, 'ascii');
  dataHeader.writeUInt32LE(slice.length, 4);

  return Buffer.concat([riffHeader, fmtHeader, fmtData, dataHeader, slice]);
}

function safeName(value) {
  return String(value || '')
    .replace(/[^A-Za-z0-9_-]+/g, '_')
    .replace(/^_+|_+$/g, '')
    .slice(0, 80);
}

const output = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];

  if (!item.binary?.audio) {
    throw new Error(`Item ${i} does not contain binary.audio`);
  }

  const audioBuffer = await this.helpers.getBinaryDataBuffer(i, 'audio');
  const wav = parseWav(audioBuffer);

  const fileSizeBytes = parseFileSizeBytes(item.binary.audio.fileSize) || audioBuffer.length;
  const durationSeconds = Number(item.json.durationSeconds || wav.durationSeconds || 0);

  const originalAudioId = safeName(`${item.json.tab || 'tab'}_${item.json.rowNumber || i + 1}`);

  const requiresSegmentation =
    durationSeconds > DIRECT_DURATION_SECONDS || fileSizeBytes > MAX_DIRECT_FILE_BYTES;

  const maxSecondsBySize = Math.max(
    MIN_SEGMENT_SECONDS,
    Math.floor((MAX_DIRECT_FILE_BYTES - 1024) / wav.byteRate)
  );

  const segmentSeconds = requiresSegmentation
    ? Math.min(PREFERRED_SEGMENT_SECONDS, maxSecondsBySize || PREFERRED_SEGMENT_SECONDS)
    : durationSeconds;

  const overlapSeconds = requiresSegmentation && durationSeconds > segmentSeconds
    ? Math.min(OVERLAP_SECONDS, Math.max(0, segmentSeconds - 1))
    : 0;

  const stepSeconds = Math.max(1, segmentSeconds - overlapSeconds);

  const plannedSegments = [];

  if (!requiresSegmentation) {
    plannedSegments.push({ start: 0, end: durationSeconds });
  } else {
    let start = 0;

    while (start < durationSeconds) {
      const end = Math.min(start + segmentSeconds, durationSeconds);
      plannedSegments.push({ start, end });

      if (end >= durationSeconds) break;
      start += stepSeconds;
    }
  }

  const totalSegments = plannedSegments.length;

  for (let segmentIndex = 0; segmentIndex < totalSegments; segmentIndex++) {
    const plan = plannedSegments[segmentIndex];

    const startByte = Math.max(
      0,
      Math.floor((plan.start * wav.byteRate) / wav.blockAlign) * wav.blockAlign
    );

    const endByte = Math.min(
      wav.dataSize,
      Math.ceil((plan.end * wav.byteRate) / wav.blockAlign) * wav.blockAlign
    );

    const dataSlice = audioBuffer.subarray(wav.dataStart + startByte, wav.dataStart + endByte);
    const segmentBuffer = requiresSegmentation
      ? createWavBuffer(wav.fmtData, dataSlice)
      : audioBuffer;

    if (requiresSegmentation && segmentBuffer.length > MAX_DIRECT_FILE_BYTES) {
      throw new Error(
        `Segment ${segmentIndex + 1}/${totalSegments} for ${originalAudioId} is still too large: ${segmentBuffer.length} bytes.`
      );
    }

    const segmentLabel = `${originalAudioId}_segment_${String(segmentIndex + 1).padStart(3, '0')}_of_${String(totalSegments).padStart(3, '0')}`;
    const segmentFileName = `${segmentLabel}.wav`;

    const binaryAudio = requiresSegmentation
      ? await this.helpers.prepareBinaryData(segmentBuffer, segmentFileName, 'audio/wav')
      : item.binary.audio;

    output.push({
      json: {
        ...item.json,
        original_audio_id: originalAudioId,
        is_segmented: requiresSegmentation,
        segmentation_reason: requiresSegmentation
          ? [
              durationSeconds > DIRECT_DURATION_SECONDS ? 'duration_over_20_minutes' : null,
              fileSizeBytes > MAX_DIRECT_FILE_BYTES ? 'file_over_20_mb' : null,
            ].filter(Boolean).join(',')
          : 'not_segmented',
        segment_index: segmentIndex,
        total_segments: totalSegments,
        segment_start_seconds: Math.round(plan.start * 1000) / 1000,
        segment_end_seconds: Math.round(plan.end * 1000) / 1000,
        segment_duration_seconds: Math.round((plan.end - plan.start) * 1000) / 1000,
        segment_overlap_seconds: overlapSeconds,
        segment_label: segmentLabel,
        segment_file_name: segmentFileName,
        original_audio_file_size_bytes: fileSizeBytes,
        segment_file_size_bytes: segmentBuffer.length,
        segment_target_seconds: segmentSeconds,
        wav_audio_format: wav.audioFormat,
        wav_channels: wav.channels,
        wav_sample_rate: wav.sampleRate,
        wav_byte_rate: wav.byteRate,
        wav_bits_per_sample: wav.bitsPerSample,
      },
      binary: {
        ...item.binary,
        audio: binaryAudio,
      },
    });
  }
}

return output;

const transcriptions = $input.all();
const segmentItems = $('Build Audio Segments').all();

function normalizeTranscript(response) {
  // OpenAI diarized_json returns speaker segments.
  if (Array.isArray(response.segments) && response.segments.length > 0) {
    return response.segments
      .map(segment => {
        const speaker = segment.speaker || 'Unknown';
        const text = String(segment.text || '').trim();
        return text ? `Speaker ${speaker}: ${text}` : '';
      })
      .filter(Boolean)
      .join('\n');
  }

  // Standard OpenAI json response returns { text: "..." }.
  if (typeof response.text === 'string') {
    return response.text.trim();
  }

  return '';
}

return transcriptions.map((item, index) => {
  const transcription = item.json || {};
  const original = segmentItems[index]?.json || {};

  const segmentTranscript = normalizeTranscript(transcription);

  return {
    json: {
      ...original,
      segmentTranscript,
      segmentTranscriptLength: segmentTranscript.length,
      openaiTranscriptionModel: transcription.model || 'gpt-4o-mini-transcribe',
      openaiTranscriptionUsage: transcription.usage || null,
      openaiTranscriptionRaw: transcription,
    },
  };
});

const items = $input.all();

function formatSeconds(totalSeconds) {
  const seconds = Math.max(0, Math.round(Number(totalSeconds || 0)));
  const h = Math.floor(seconds / 3600);
  const m = Math.floor((seconds % 3600) / 60);
  const s = seconds % 60;

  if (h > 0) {
    return `${h}:${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`;
  }

  return `${m}:${String(s).padStart(2, '0')}`;
}

const groups = {};

for (const item of items) {
  const json = item.json || {};
  const id = json.original_audio_id || `${json.tab || 'tab'}_${json.rowNumber || 'row'}`;

  if (!groups[id]) {
    groups[id] = [];
  }

  groups[id].push(json);
}

const output = [];

for (const [originalAudioId, segments] of Object.entries(groups)) {
  segments.sort((a, b) => Number(a.segment_index || 0) - Number(b.segment_index || 0));

  const expectedSegments = Number(segments[0]?.total_segments || segments.length);

  if (segments.length !== expectedSegments) {
    throw new Error(
      `Missing transcript segments for ${originalAudioId}. Expected ${expectedSegments}, received ${segments.length}.`
    );
  }

  const transcriptParts = segments
    .map(segment => {
      const text = String(segment.segmentTranscript || '').trim();
      if (!text) return '';

      if (expectedSegments <= 1) {
        return text;
      }

      const start = formatSeconds(segment.segment_start_seconds);
      const end = formatSeconds(segment.segment_end_seconds);
      return `[Segment ${Number(segment.segment_index) + 1}/${expectedSegments} | ${start}-${end}]\n${text}`;
    })
    .filter(Boolean);

  const fullTranscript = transcriptParts.join('\n\n');

  output.push({
    json: {
      ...segments[0],
      original_audio_id: originalAudioId,
      transcriptText: fullTranscript,
      transcriptTextLength: fullTranscript.length,
      segmentsProcessed: segments.length,
      total_segments: expectedSegments,
      readyForParser: true,
      segmentTranscripts: segments.map(segment => ({
        segment_index: segment.segment_index,
        segment_label: segment.segment_label,
        start_seconds: segment.segment_start_seconds,
        end_seconds: segment.segment_end_seconds,
        text: segment.segmentTranscript || '',
      })),
    },
  });
}

return output;

const response = $input.first().json;
const original = $('Aggregate Segment Transcripts').first().json;

function extractOpenAIText(response) {
  if (response.output_text) {
    return response.output_text;
  }

  const text = response.output?.[0]?.content?.[0]?.text;

  if (!text) {
    throw new Error('OpenAI response does not contain output[0].content[0].text');
  }

  return text;
}

const rawText = extractOpenAIText(response);

let review;

try {
  review = JSON.parse(rawText);
} catch (error) {
  throw new Error(`Could not parse OpenAI review JSON: ${error.message}. Raw text: ${rawText}`);
}

return [
  {
    json: {
      ...original,

      professionalGreeting: review.professional_greeting,
      almFrameworkA: review.alm_framework_a,
      almFrameworkL: review.alm_framework_l,
      almFrameworkM: review.alm_framework_m,
      almFrameworkBonus: review.alm_framework_bonus,
      successfulAppointmentSet: review.successful_appointment_set,
      potentiallyCounterproductiveActions: review.potentially_counterproductive_actions,
      discussedPropertySpecifics: review.discussed_property_specifics,
      askedPreQualified: review.asked_pre_qualified,
      reactiveNotProactive: review.reactive_not_proactive,
      discussedBuyersAgency: review.discussed_buyers_agency,
      askedWorkingWithAnotherAgent: review.asked_working_with_another_agent,
      commentsForSheet: review.comments,

      statusForSheet: 'OpenAI Completed',

      openaiReviewRaw: review
    }
  }
];

const items = $input.all();

const MONTHS = {
  jan: 'January', january: 'January',
  feb: 'February', february: 'February',
  mar: 'March', march: 'March',
  apr: 'April', april: 'April',
  may: 'May',
  jun: 'June', june: 'June',
  jul: 'July', july: 'July',
  aug: 'August', august: 'August',
  sep: 'September', sept: 'September', september: 'September',
  oct: 'October', october: 'October',
  nov: 'November', november: 'November',
  dec: 'December', december: 'December',
};

function escapeRegex(value) {
  return String(value).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function looksLikeBase64Url(value) {
  const text = String(value || '').trim();

  return (
    text.length > 30 &&
    !/\s/.test(text) &&
    !text.includes('<') &&
    /^[A-Za-z0-9+/_=-]+$/.test(text)
  );
}

function decodeBase64Url(value) {
  if (!value || typeof value !== 'string') return '';

  try {
    const normalized = value.replace(/-/g, '+').replace(/_/g, '/');
    const padded = normalized + '='.repeat((4 - normalized.length % 4) % 4);
    return Buffer.from(padded, 'base64').toString('utf8');
  } catch {
    return value;
  }
}

function decodeQuotedPrintable(value) {
  return String(value || '')
    .replace(/=\r?\n/g, '')
    .replace(/=([A-Fa-f0-9]{2})/g, (_, hex) =>
      String.fromCharCode(parseInt(hex, 16))
    );
}

function decodeContent(value) {
  let output = String(value || '');

  if (looksLikeBase64Url(output)) {
    output = decodeBase64Url(output);
  }

  if (/=[A-Fa-f0-9]{2}|=\r?\n/.test(output)) {
    output = decodeQuotedPrintable(output);
  }

  return output;
}

function htmlDecode(value) {
  return String(value || '')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&#39;/gi, "'")
    .replace(/&apos;/gi, "'")
    .replace(/&quot;/gi, '"')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>');
}

function clean(value) {
  return htmlDecode(decodeContent(value))
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function cleanUrl(value) {
  return htmlDecode(decodeQuotedPrintable(String(value || '')))
    .replace(/\s+/g, '')
    .replace(/[>"')\].,;]+$/g, '')
    .trim();
}

function extractBetweenLabels(source, label, nextLabels = []) {
  const escapedLabel = escapeRegex(label);

  const escapedNextLabels = nextLabels
    .map(escapeRegex)
    .join('|');

  const pattern = escapedNextLabels
    ? new RegExp(`${escapedLabel}\\s+(.+?)\\s+(?=${escapedNextLabels}\\s+)`, 'i')
    : new RegExp(`${escapedLabel}\\s+(.+)$`, 'i');

  const match = source.match(pattern);
  return match ? match[1].trim() : '';
}

function getPayloadContent(payload, mimeType) {
  if (!payload) return '';

  let output = '';

  function walk(part) {
    if (!part) return;

    if (part.mimeType === mimeType && part.body?.data) {
      output += decodeContent(part.body.data) + ' ';
    }

    if (Array.isArray(part.parts)) {
      part.parts.forEach(walk);
    }
  }

  walk(payload);
  return output.trim();
}

function extractRecordingLink(html, text = '') {
  const decodedHtml = decodeContent(html || '');
  const combined = `${decodedHtml}\n${text || ''}`;

  const links = [];

  const anchorRegex =
    /<a\b[^>]*href\s*=\s*(?:"([^"]+)"|'([^']+)'|([^'">\s]+))[^>]*>([\s\S]*?)<\/a>/gi;

  let match;

  while ((match = anchorRegex.exec(combined)) !== null) {
    const href = cleanUrl(match[1] || match[2] || match[3]);
    const label = clean(match[4]);

    links.push({ href, label });

    if (/listen\s+to\s+recording/i.test(label)) {
      return href;
    }

    if (/recording/i.test(label) && !/unsubscribe|preferences|n8n/i.test(href)) {
      return href;
    }
  }

  // Fallback: href appears near the word Recording
  const nearRecordingPatterns = [
    /Recording[\s\S]{0,1200}?href\s*=\s*(?:"([^"]+)"|'([^']+)'|([^'">\s]+))/i,
    /href\s*=\s*(?:"([^"]+)"|'([^']+)'|([^'">\s]+))[\s\S]{0,1200}?Recording/i,
    /Listen\s+to\s+recording[\s\S]{0,1200}?(https?:\/\/[^\s"'<>]+)/i,
    /Recording[\s\S]{0,1200}?(https?:\/\/[^\s"'<>]+)/i,
  ];

  for (const pattern of nearRecordingPatterns) {
    const result = combined.match(pattern);
    if (result) {
      return cleanUrl(result[1] || result[2] || result[3]);
    }
  }

  // Last fallback: choose a likely recording/audio/call link, but avoid footer links
  const likelyLink = links.find(link =>
    /(record|recording|audio|call|voicemail|zillow)/i.test(link.href) &&
    !/(unsubscribe|preferences|n8n)/i.test(link.href)
  );

  return likelyLink ? likelyLink.href : '';
}

function getFallbackYear(json = {}) {
  if (json.internalDate) {
    const d = new Date(Number(json.internalDate));
    if (!Number.isNaN(d.getTime())) return d.getFullYear();
  }

  if (json.date) {
    const d = new Date(json.date);
    if (!Number.isNaN(d.getTime())) return d.getFullYear();
  }

  if (json.headers?.date) {
    const d = new Date(json.headers.date);
    if (!Number.isNaN(d.getTime())) return d.getFullYear();
  }

  return new Date().getFullYear();
}

function formatCallDate(value, fallbackYear) {
  if (!value) return '';

  let dateText = clean(value)
    .replace(/,/g, '')
    .replace(/\bat\b/gi, ' ')
    .replace(/(\d)(am|pm)\b/gi, '$1 $2')
    .replace(/\s+/g, ' ')
    .trim();

  let match;

  // May 22 2026 5:30 PM
  match = dateText.match(
    /^([A-Za-z]+)\s+(\d{1,2})\s+(\d{4})\s+(\d{1,2})(?::(\d{2}))?\s*(AM|PM)$/i
  );

  if (match) {
    const [, monthRaw, day, year, hour, minute = '00', ampm] = match;
    const month = MONTHS[monthRaw.toLowerCase()] || monthRaw;
    return `${Number(day)} ${month} ${year} at ${Number(hour)}:${minute.padStart(2, '0')} ${ampm.toUpperCase()}`;
  }

  // May 22 5:30pm
  match = dateText.match(
    /^([A-Za-z]+)\s+(\d{1,2})\s+(\d{1,2})(?::(\d{2}))?\s*(AM|PM)$/i
  );

  if (match) {
    const [, monthRaw, day, hour, minute = '00', ampm] = match;
    const month = MONTHS[monthRaw.toLowerCase()] || monthRaw;
    const year = fallbackYear || new Date().getFullYear();

    return `${Number(day)} ${month} ${year} at ${Number(hour)}:${minute.padStart(2, '0')} ${ampm.toUpperCase()}`;
  }

  // 05/22/2026 5:30 PM
  match = dateText.match(
    /^(\d{1,2})\/(\d{1,2})\/(\d{2,4})\s+(\d{1,2})(?::(\d{2}))?\s*(AM|PM)$/i
  );

  if (match) {
    let [, monthNumber, day, year, hour, minute = '00', ampm] = match;

    if (year.length === 2) year = `20${year}`;

    const monthNames = [
      'January', 'February', 'March', 'April', 'May', 'June',
      'July', 'August', 'September', 'October', 'November', 'December',
    ];

    const month = monthNames[Number(monthNumber) - 1] || monthNumber;

    return `${Number(day)} ${month} ${year} at ${Number(hour)}:${minute.padStart(2, '0')} ${ampm.toUpperCase()}`;
  }

  return value;
}

function escapeSheetFormula(value) {
  return String(value || '').replace(/"/g, '""');
}

return items.map(item => {
  const json = item.json || {};

  const html = [
    json.html,
    json.textHtml,
    json.body?.html,
    json.body?.textHtml,
    getPayloadContent(json.payload, 'text/html'),
    json.payload?.body?.data,
  ]
    .map(decodeContent)
    .filter(Boolean)
    .join('\n');

  const text = [
    json.text,
    json.textPlain,
    json.body?.text,
    json.body?.textPlain,
    getPayloadContent(json.payload, 'text/plain'),
    json.snippet,
  ]
    .map(decodeContent)
    .filter(Boolean)
    .join('\n');

  const source = clean(`${text} ${html}`);

  const labels = [
    'Office',
    'Property Address',
    'Price',
    'Agent',
    'Lead',
    'Phone',
    'Call Date',
    'Recording',
  ];

  const office = extractBetweenLabels(source, 'Office', labels.slice(1));
  const propertyAddress = extractBetweenLabels(source, 'Property Address', labels.slice(2));
  const price = extractBetweenLabels(source, 'Price', labels.slice(3));
  const agent = extractBetweenLabels(source, 'Agent', labels.slice(4));
  const lead = extractBetweenLabels(source, 'Lead', labels.slice(5));
  const phone = extractBetweenLabels(source, 'Phone', labels.slice(6));
  const rawCallDate = extractBetweenLabels(source, 'Call Date', labels.slice(7));

  const recordingLink = extractRecordingLink(html, text);

  return {
    json: {
      emailId: json.id || '',
      office,
      propertyAddress,
      price,
      agent,
      lead,
      phone,
      callDate: formatCallDate(rawCallDate, getFallbackYear(json)),
      rawCallDate,
      recordingLink,

      // Optional: use this in Google Sheets for a clickable label
      recordingFormula: recordingLink
        ? `=HYPERLINK("${escapeSheetFormula(recordingLink)}","Listen to recording")`
        : '',

      // Debug helper
      recordingLinkFound: Boolean(recordingLink),
    },
  };
});
